static bool check_privilege(const struct privilege_context *ctx, uint32_t required_priv)
{
    if ((ctx->privileges & required_priv) == required_priv) {
        printk("[PRIV] %s (uid=%u): privilege check PASSED for 0x%02x\n",
               ctx->name, ctx->uid, required_priv);
        return true;
    }
    printk("[PRIV] %s (uid=%u): privilege check FAILED for 0x%02x (has 0x%02x)\n",
           ctx->name, ctx->uid, required_priv, ctx->privileges);
    return false;
}

