static int submit_admin_operation(struct admin_operation *op)
{
    int ret = 0;

    k_mutex_lock(&ops_mutex, K_FOREVER);

    if (pending_ops_count >= MAX_PENDING_OPS) {
        printk("[OPS] Operation queue full\n");
        k_mutex_unlock(&ops_mutex);
        return -ENOMEM;
    }

    memcpy(&pending_ops[pending_ops_tail], op, sizeof(struct admin_operation));
    pending_ops[pending_ops_tail].status = OP_STATUS_PENDING;
    pending_ops_tail = (pending_ops_tail + 1) % MAX_PENDING_OPS;
    pending_ops_count++;

    printk("[OPS] User (uid=%u) submitted operation type %d\n",
           op->requester_uid, op->op_type);

    k_mutex_unlock(&ops_mutex);
    k_sem_give(&ops_available_sem);

    /* Wait for operation to complete */
    k_sem_take(&op_complete_sem, K_MSEC(5000));

    /* Check the result */
    k_mutex_lock(&ops_mutex, K_FOREVER);
    int head_idx = (pending_ops_head - 1 + MAX_PENDING_OPS) % MAX_PENDING_OPS;
    if (pending_ops[head_idx].status == OP_STATUS_DENIED) {
        ret = -EACCES;
    } else if (pending_ops[head_idx].status == OP_STATUS_COMPLETED) {
        if (op->op_type == OP_READ_CONFIG) {
            strncpy(op->params.config_read.result,
                    pending_ops[head_idx].params.config_read.result,
                    MAX_CONFIG_VAL_LEN);
        }
        ret = 0;
    }
    k_mutex_unlock(&ops_mutex);

    return ret;
}

static bool validate_operation_request(const struct admin_operation *op)
{
    switch (op->op_type) {
    case OP_FLASH_WRITE:
        if (op->params.flash_write.offset + op->params.flash_write.len > FLASH_SIM_SIZE) {
            printk("[ADMIN] Invalid flash write parameters\n");
            return false;
        }
        if (op->params.flash_write.len > sizeof(op->params.flash_write.data)) {
            printk("[ADMIN] Flash write data too large\n");
            return false;
        }
        return true;
    case OP_SYS_CONFIG:
        if (strlen(op->params.config_modify.key) == 0) {
            printk("[ADMIN] Empty config key\n");
            return false;
        }
        return true;
    case OP_READ_CONFIG:
        if (strlen(op->params.config_read.key) == 0) {
            printk("[ADMIN] Empty read key\n");
            return false;
        }
        return true;
    default:
        printk("[ADMIN] Unknown operation type %d\n", op->op_type);
        return false;
    }
}

static void process_admin_operation(struct admin_operation *op)
{
    int ret;

    printk("[ADMIN] Processing operation type %d from uid=%u\n",
           op->op_type, op->requester_uid);

    if (!validate_operation_request(op)) {
        op->status = OP_STATUS_DENIED;
        printk("[ADMIN] Operation validation failed\n");
        return;
    }

    /* Admin escalates privileges on behalf of user */
    switch (op->op_type) {
    case OP_FLASH_WRITE:
        printk("[ADMIN] Executing flash write on behalf of uid=%u\n",
               op->requester_uid);
        ret = flash_write(&admin_ctx,
                          op->params.flash_write.offset,
                          op->params.flash_write.data,
                          op->params.flash_write.len);
        if (ret == 0) {
            op->status = OP_STATUS_COMPLETED;
            printk("[ADMIN] Flash write completed successfully\n");
        } else {
            op->status = OP_STATUS_DENIED;
            printk("[ADMIN] Flash write failed: %d\n", ret);
        }
        break;

    case OP_SYS_CONFIG:
        printk("[ADMIN] Executing config modify on behalf of uid=%u\n",
               op->requester_uid);
        ret = config_set(&admin_ctx,
                         op->params.config_modify.key,
                         op->params.config_modify.value);
        if (ret == 0) {
            op->status = OP_STATUS_COMPLETED;
            printk("[ADMIN] Config modify completed successfully\n");
        } else {
            op->status = OP_STATUS_DENIED;
            printk("[ADMIN] Config modify failed: %d\n", ret);
        }
        break;

    case OP_READ_CONFIG:
        printk("[ADMIN] Executing config read on behalf of uid=%u\n",
               op->requester_uid);
        ret = config_get(&admin_ctx,
                         op->params.config_read.key,
                         op->params.config_read.result,
                         MAX_CONFIG_VAL_LEN);
        if (ret == 0) {
            op->status = OP_STATUS_COMPLETED;
        } else {
            op->status = OP_STATUS_DENIED;
        }
        break;

    default:
        op->status = OP_STATUS_DENIED;
        break;
    }
}

static void admin_task(void *p1, void *p2, void *p3)
{
    ARG_UNUSED(p1);
    ARG_UNUSED(p2);
    ARG_UNUSED(p3);

    printk("[ADMIN] Admin task started (uid=%u, privs=0x%02x)\n",
           admin_ctx.uid, admin_ctx.privileges);

    /* Perform initial admin operations directly */
    printk("\n=== Admin Direct Operations ===\n");

    /* Write initial data to flash */
    uint8_t init_data[] = {0xDE, 0xAD, 0xBE, 0xEF, 0xCA, 0xFE};
    flash_write(&admin_ctx, 0, init_data, sizeof(init_data));

    /* Read back */
    uint8_t read_buf[6];
    flash_read(&admin_ctx, 0, read_buf, sizeof(read_buf));
    printk("[ADMIN] Flash readback: ");
    for (int i = 0; i < (int)sizeof(read_buf); i++) {
        printk("0x%02X ", read_buf[i]);
    }
    printk("\n");

    /* Modify system config */
    config_set(&admin_ctx, "log_level", "debug");
    config_set(&admin_ctx, "network_mode", "station");

    char val[MAX_CONFIG_VAL_LEN];
    config_get(&admin_ctx, "hostname", val, sizeof(val));
    config_get(&admin_ctx, "log_level", val, sizeof(val));

    printk("\n=== Admin Processing User Requests ===\n");

    /* Now process user-submitted operations */
    while (1) {
        k_sem_take(&ops_available_sem, K_FOREVER);

        k_mutex_lock(&ops_mutex, K_FOREVER);

        if (pending_ops_count > 0) {
            struct admin_operation *op = &pending_ops[pending_ops_head];

            process_admin_operation(op);

            pending_ops_head = (pending_ops_head + 1) % MAX_PENDING_OPS;
            pending_ops_count--;
        }

        k_mutex_unlock(&ops_mutex);

        /* Signal that operation is complete */
        k_sem_give(&op_complete_sem);
    }
}

