int main(void)
{
    printk("\n========================================\n");
    printk("  Embedded Permission System Demo\n");
    printk("  Zephyr RTOS Privilege Management\n");
    printk("========================================\n\n");

    /* Initialize subsystems */
    init_system_config();
    init_flash_memory();
    memset(pending_ops, 0, sizeof(pending_ops));

    printk("[INIT] System config initialized with %d entries\n", sys_config.count);
    printk("[INIT] Simulated flash memory initialized (%d bytes)\n", FLASH_SIM_SIZE);
    printk("[INIT] Admin privileges: 0x%02x\n", admin_ctx.privileges);
    printk("[INIT] User privileges:  0x%02x\n", user_ctx.privileges);
    printk("\n");

    /* Create admin task (higher priority) */
    k_thread_create(&admin_thread_data, admin_stack, STACK_SIZE,
                    admin_task, NULL, NULL, NULL,
                    ADMIN_PRIORITY, 0, K_NO_WAIT);
    k_thread_name_set(&admin_thread_data, "admin_task");

    /* Create user task (lower priority) */
    k_thread_create(&user_thread_data, user_stack, STACK_SIZE,
                    user_task, NULL, NULL, NULL,
                    USER_PRIORITY, 0, K_NO_WAIT);
    k_thread_name_set(&user_thread_data, "user_task");

    printk("[INIT] Tasks created. System running.\n\n");

    return 0;
}